"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[47e4],{117528:e=>{e.exports=JSON.parse('{"tag":{"label":"equipment","permalink":"/dst-api-webdocs/docs/tags/equipment","allTagsPath":"/dst-api-webdocs/docs/tags","count":77,"items":[{"id":"game-scripts/prefabs/amulet","title":"Amulet","description":"Manages amulet-specific behaviors when equipped or unequipped, including healing, freezing, sanity effects, building discounts, pickup ability, and light emission, depending on the amulet color variant.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/amulet"},{"id":"game-scripts/components/armor","title":"Armor","description":"Manages durability, damage absorption, and weakness modifiers for armor entities in combat.","permalink":"/dst-api-webdocs/docs/game-scripts/components/armor"},{"id":"game-scripts/prefabs/armor_bramble","title":"Armor Bramble","description":"A wearable armor item that triggers thorn-based retaliation effects when the wearer is blocked or attacks, conditional on skill tree activation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_bramble"},{"id":"game-scripts/prefabs/armor_carrotlure","title":"Armor Carrotlure","description":"An equippable armor item that periodically attracts and extends loyalty of rabbit followers within range of its owner, who must be a leader.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_carrotlure"},{"id":"game-scripts/prefabs/armor_dragonfly","title":"Armor Dragonfly","description":"Provides fire-resistant body armor with a chance to ignite attackers on successful block or parry.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_dragonfly"},{"id":"game-scripts/prefabs/armor_grass","title":"Armor Grass","description":"A wearable grass armor item that provides basic damage absorption and integrates with skin-swapping, fuel, and flammability systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_grass"},{"id":"game-scripts/prefabs/armor_lunarplant","title":"Armor Lunarplant","description":"Provides armor protection, planar defense, damage reflection, and set-bonus resistances for equippable gear, with conditional behaviors for plantkin characters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_lunarplant"},{"id":"game-scripts/prefabs/armor_marble","title":"Armor Marble","description":"A piece of heavy armor that provides high damage absorption at the cost of movement speed, with special marble-sound effects when blocking attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_marble"},{"id":"game-scripts/prefabs/armor_ruins","title":"Armor Ruins","description":"A wearable piece of high-defense armor that provides substantial damage absorption and integrates with DST\u2019s skinning and shadow level systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_ruins"},{"id":"game-scripts/prefabs/armor_sanity","title":"Armor Sanity","description":"Provides protective armor and applies a sanity penalty to the wearer when damage is blocked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_sanity"},{"id":"game-scripts/prefabs/armor_skeleton","title":"Armor Skeleton","description":"Grants the wearer temporary resistance to multiple damage types by consuming nightmare fuel and spawning visual shield effects when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_skeleton"},{"id":"game-scripts/prefabs/armor_slurper","title":"Armor Slurper","description":"A wearable inventory item that reduces the owner\'s hunger burn rate while consuming its own fuel over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_slurper"},{"id":"game-scripts/prefabs/armor_snurtleshell","title":"Armor Snurtleshell","description":"A wearable body armor that grants increased damage absorption when the wearer enters the shell state, and disables absorption upon exiting it.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_snurtleshell"},{"id":"game-scripts/prefabs/armor_voidcloth","title":"Armor Voidcloth","description":"A wearable item that grants shadow-aligned resistance, planar defense, and sets a negative sanity aura when equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_voidcloth"},{"id":"game-scripts/prefabs/armor_wood","title":"Armor Wood","description":"Provides wooden armor with damage absorption, fuel properties, and visual skin-swapping logic for equipping.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_wood"},{"id":"game-scripts/prefabs/armor_yoth_knight","title":"Armor Yoth Knight","description":"A wearable piece of heavy metal armor that provides protection and triggers set-bonus effects when equipped as part of the Yoth Knight equipment set.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_yoth_knight"},{"id":"game-scripts/prefabs/backpack","title":"Backpack","description":"Manages equippable storage behavior with skin-specific visual FX and inventory interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/backpack"},{"id":"game-scripts/prefabs/beard_sack","title":"Beard Sack","description":"A wearable container prefab for Beardlings that opens on equip and closes on unequip, functioning as a special inventory slot in the Beard.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beard_sack"},{"id":"game-scripts/prefabs/beargervest","title":"Beargervest","description":"Defines the Bearger Vest prefab, an equipable body slot item that provides insulation and slows hunger drain while consuming durability.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beargervest"},{"id":"game-scripts/prefabs/bomb_lunarplant","title":"Bomb Lunarplant","description":"A ranged explosive weapon that launches a spinning projectile to detonate on impact, dealing planar damage in an area.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bomb_lunarplant"},{"id":"game-scripts/prefabs/candybag","title":"Candybag","description":"A wearable container item that functions as a backpack with fire-sensitive locking behavior and Ashdrop mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/candybag"},{"id":"game-scripts/prefabs/cane","title":"Cane","description":"A wearable weapon tool that modifies the owner\'s movement speed and deals damage when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cane"},{"id":"game-scripts/prefabs/chum","title":"Chum","description":"A throwable fishing bait item that spawns chum or a green splash effect depending on terrain, and creates an AOE when thrown into ocean tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum"},{"id":"game-scripts/prefabs/costumes","title":"Costumes","description":"Factory function for creating costume prefabs with equippable body armor and visual skin overrides.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/costumes"},{"id":"game-scripts/prefabs/diviningrod","title":"Diviningrod","description":"Tracks proximity to teleportato components and updates description, sound, and visual feedback when equipped by a player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/diviningrod"},{"id":"game-scripts/prefabs/dumbbells","title":"Dumbbells","description":"Implements a set of multipurpose workout equipment prefabs with weighted, elemental, and temperature-based variants, enabling melee combat, AOE attacks, and environmental thermoregulation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dumbbells"},{"id":"game-scripts/components/equippable","title":"Equippable","description":"Manages item equipping behavior, including slot assignment, unequip prevention, movement speed modifiers, dapperness, moisture, and equip/unequip callbacks for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/equippable"},{"id":"game-scripts/components/equippable_replica","title":"Equippable Replica","description":"Manages network-replicated equipment slot and restriction logic for equippable items in DST\'s client-server architecture.","permalink":"/dst-api-webdocs/docs/game-scripts/components/equippable_replica"},{"id":"game-scripts/widgets/equipslot","title":"Equipslot","description":"Manages interactive equipment slots on the UI, handling item equipping, unequipping, and highlighting based on active items.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/equipslot"},{"id":"game-scripts/prefabs/fishingnet","title":"Fishingnet","description":"Adds fishing net functionality and finite durability to the fishing net item, including visual equip animations and burn prevention.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishingnet"},{"id":"game-scripts/prefabs/fishingrod","title":"Fishingrod","description":"A multi-use tool item that allows characters to fish, deals damage in combat, and handles visual and functional behavior when equipped or used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishingrod"},{"id":"game-scripts/prefabs/flotationcushion","title":"Flotationcushion","description":"A prefab item that provides buoyancy support when equipped by a player, enabling underwater movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flotationcushion"},{"id":"game-scripts/prefabs/glass_spike","title":"Glass Spike","description":"Creates deployable glass obstacles that can be hammered into blocks and used as defensive equipment with unique visual and behavioral states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glass_spike"},{"id":"game-scripts/prefabs/hammer","title":"Hammer","description":"A durable tool and weapon used for destroying structures and enemies; has finite durability and triggers skin overrides when equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hammer"},{"id":"game-scripts/prefabs/horseshoe","title":"Horseshoe","description":"A wearable lucky item that grants luck bonuses to the player when equipped, with animated shine effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/horseshoe"},{"id":"game-scripts/components/inventory","title":"Inventory","description":"Manages the storage, equipping, and inventory interactions for player entities, including slot-based item management, equipment handling, and container integration.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventory"},{"id":"game-scripts/prefabs/krampus_sack","title":"Krampus Sack","description":"A wearable container item that opens when equipped and closes when unequipped, providing inventory storage with water resistance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/krampus_sack"},{"id":"game-scripts/components/luckitem","title":"Luckitem","description":"Manages luck contribution from an item to its owner, adjusting based on equipped state and stack size.","permalink":"/dst-api-webdocs/docs/game-scripts/components/luckitem"},{"id":"game-scripts/components/lunarplant_tentacle_weapon","title":"Lunarplant Tentacle Weapon","description":"Spawns lunar tentacles as secondary attacks when equipped and used in combat, conditional on skill tree activation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarplant_tentacle_weapon"},{"id":"game-scripts/components/magician","title":"Magician","description":"Manages the state and lifecycle of a magician tool currently being used by an entity, including equipping, holding, and dropping behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/magician"},{"id":"game-scripts/components/magiciantool","title":"Magiciantool","description":"Manages the usage lifecycle of magical tools by tracking user context and invoking custom callbacks when tools are started or stopped being used.","permalink":"/dst-api-webdocs/docs/game-scripts/components/magiciantool"},{"id":"game-scripts/prefabs/mininglantern","title":"Mininglantern","description":"Manages the behavior, lighting, fuel consumption, and equip/unequip interactions for the Mining Lantern item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mininglantern"},{"id":"game-scripts/prefabs/oar","title":"Oar","description":"Provides the logic and configuration for oar items used in boat rowing, including durability tracking, waterproofing, and attachment to entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oar"},{"id":"game-scripts/prefabs/oceanfishingrod","title":"Oceanfishingrod","description":"Implements the ocean fishing rod item, managing tackle slots, reticule targeting, and fishing state transitions in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishingrod"},{"id":"game-scripts/components/oceanfishingrod_replica","title":"Oceanfishingrod Replica","description":"Manages networked state for the ocean fishing rod, including hook target, line tension level, and maximum cast distance.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingrod_replica"},{"id":"game-scripts/components/oceanfishingtackle","title":"Oceanfishingtackle","description":"Manages casting data and lure configuration for ocean fishing mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingtackle"},{"id":"game-scripts/prefabs/pillow_equipment","title":"Pillow equipment","description":"Generates prefabs for body and hand pillows, including associated attack FX, with equipment and weapon behavior tailored for combat and minigames.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pillow_equipment"},{"id":"game-scripts/components/playerhearing","title":"Playerhearing","description":"Manages dynamic audio DSP filters applied to the player based on equipped items, such as muffling hats.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerhearing"},{"id":"game-scripts/components/playerinspectable","title":"Playerinspectable","description":"Syncs player equipment and skill selections to the network for client-side rendering of character appearance.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerinspectable"},{"id":"game-scripts/prefabs/pocketwatch_weapon","title":"Pocketwatch Weapon","description":"A weaponized pocketwatch that toggles between shadow and depleted states based on fuel level, altering damage and emitting visual effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketwatch_weapon"},{"id":"game-scripts/prefabs/ruins_bat","title":"Ruins Bat","description":"A consumable equippable weapon that allows the player to summon shadow tentacles on attack, with a limited number of uses and shadow level scaling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_bat"},{"id":"game-scripts/prefabs/saddle","title":"Saddle","description":"Provides mount-related stats and behaviors for saddle items, including damage/speed bonuses, finite durability, and optional special effects like planar resistance or visual overlays.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saddle"},{"id":"game-scripts/components/setbonus","title":"Setbonus","description":"Manages equipment set bonus logic for entities, enabling or disabling set-based effects when matching gear is equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/components/setbonus"},{"id":"game-scripts/prefabs/sewing_mannequin","title":"Sewing Mannequin","description":"Acts as a wearable equipment storage and equipment-swap target for players using the Stageplay Set crafting recipe.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sewing_mannequin"},{"id":"game-scripts/components/shadowdominance","title":"Shadowdominance","description":"Manages the \\"shadowdominance\\" tag on an entity based on equip state and presence of other shadow-dominant items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowdominance"},{"id":"game-scripts/prefabs/shell_cluster","title":"Shell Cluster","description":"A breakable environmental object that drops singing shells when mined and can be equipped as body armor.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shell_cluster"},{"id":"game-scripts/prefabs/shovel","title":"Shovel","description":"Implements the shovel and golden shovel prefabs with dig capability, limited durability, weapon damage, and equip/unequip animation handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel"},{"id":"game-scripts/prefabs/shovel_lunarplant","title":"Shovel Lunarplant","description":"A lunar plant\u2013themed shovel that grants bonus damage and planar damage when equipped alongside a Lunar Plant Hat, with dynamic behavior based on breakage state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shovel_lunarplant"},{"id":"game-scripts/components/skinner_beefalo","title":"Skinner Beefalo","description":"Manages wearable equipment slots (body, feet, head, horn, tail) and skin application for beefalo entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/skinner_beefalo"},{"id":"game-scripts/widgets/skinsandequipmentpuppet","title":"Skinsandequipmentpuppet","description":"A UI widget that renders a character skin and equipment preview puppet, handling character selection fallback, skin overrides, and animation updates.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/skinsandequipmentpuppet"},{"id":"game-scripts/prefabs/slingshot","title":"Slingshot","description":"Manages the core functionality, visual layers, equipment, and projectile launching behavior for the slingshot weapon and its variants in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshot"},{"id":"game-scripts/prefabs/slingshotpart_defs","title":"Slingshotpart Defs","description":"Defines modding configurations and installation/uninstallation logic for slingshot parts (bands, frames, handles) in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotpart_defs"},{"id":"game-scripts/prefabs/slingshotparts","title":"Slingshotparts","description":"Defines prefabs for slingshot parts (bands, frames, handles) and registers them with appropriate components and tags for installation in slingshot mod containers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotparts"},{"id":"game-scripts/prefabs/spear","title":"Spear","description":"A consumable spear weapon with limited durability that deals fixed damage and supports skin overrides on equip/unequip.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear"},{"id":"game-scripts/prefabs/spear_wathgrithr","title":"Spear Wathgrithr","description":"Implements Wathgrithr\'s spear variants, including basic, lightning, and fully charged lightning spear with dynamic equipment effects, skill-based ability scaling, and lunge-based lightning attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear_wathgrithr"},{"id":"game-scripts/prefabs/spicepack","title":"Spicepack","description":"A wearable backpack item that provides inventory storage, functions as a food preserver, and responds to fire ignition and extinguishing by locking/unlocking its contents.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spicepack"},{"id":"game-scripts/prefabs/sweatervest","title":"Sweatervest","description":"Provides insulation and temporary heat protection when equipped, depleting fuel over time while worn.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sweatervest"},{"id":"game-scripts/prefabs/trunkvest","title":"Trunkvest","description":"A seasonal armor prefab that provides insulation and waterproofer properties, consuming fuel while equipped to prevent hypothermia or overheating.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trunkvest"},{"id":"game-scripts/prefabs/umbrella","title":"Umbrella","description":"An equippable item that provides rain protection, insulation, and temporary coverage, consuming fuel or perishing over time depending on variant.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/umbrella"},{"id":"game-scripts/components/useableitem","title":"UseableItem","description":"Manages the \\"in use\\" state of an equippable item and provides callbacks for when it starts or stops being used.","permalink":"/dst-api-webdocs/docs/game-scripts/components/useableitem"},{"id":"game-scripts/prefabs/veggies","title":"Veggies","description":"Generates prefabs and logic for vegetables, their cooked/dried variants, oversized variants with weight-based physics and equippable functionality, and seed deployment mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/veggies"},{"id":"game-scripts/prefabs/voidcloth_boomerang","title":"Voidcloth Boomerang","description":"Manages the voidcloth boomerang weapon, including its equippable behavior, projectile generation, set-bonus activation when paired with a voidcloth hat, and dynamic damage scaling during return flight.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/voidcloth_boomerang"},{"id":"game-scripts/prefabs/voidcloth_umbrella","title":"Voidcloth Umbrella","description":"A magical rain-protection item that deploys a dome to block rain and acid rain while consuming magic fuel, with unique behavior when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/voidcloth_umbrella"},{"id":"game-scripts/prefabs/wateringcan","title":"Wateringcan","description":"A tool prefab that holds water for plant care, providing wetness, cooling, and protection effects when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wateringcan"},{"id":"game-scripts/prefabs/waterprojectiles","title":"Waterprojectiles","description":"Defines prefabs and behaviors for water-based projectiles (snowballs, water balloons, ink splats, bile splats, and water streaks), each implementing custom collision handling, projectile physics, and fire suppression or status effects via the wateryprotection and complexprojectile components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterprojectiles"},{"id":"game-scripts/prefabs/winona_remote","title":"Winona Remote","description":"Manages spell selection, deployment targeting, and battery-powered operations for Winona\'s engineer remote gadget, including circuit connections, charging logic, and elemental ability validation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_remote"},{"id":"game-scripts/prefabs/wortox_nabbag","title":"Wortox Nabbag","description":"Manages Wortox\'s soul-collecting bug net, dynamically adjusting weapon damage, visual size, and effects based on inventory soul count and slot usage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_nabbag"}],"unlisted":false}}')}}]);